import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        // Build adjacency list
        Map<Long, List<long[]>> adj = new HashMap<>();
        for (long u : edges) {
            adj.putIfAbsent(u, new ArrayList<>());
            long v = edges[0][1];
            long w = edges[0][2];
            adj.get(u).add(new long[]{v, w});
        }

        // Dijkstra's algorithm with state tracking (node, switch_used)
        // We use a priority queue to track the minimum cost to reach each state
        // (node, switch_used) where switch_used is a boolean (0 or 1)
        // We use a distance array to track the minimum cost to reach each state
        // Initialize distance with infinity
        long[][] dist = new long[(int)n][2];
        for (int i = 0; i < n; i++) {
            Arrays.fill(dist[i], Long.MAX_VALUE);
        }
        dist[0][0] = 0;

        // Priority queue: [cost, node, switch_used]
        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        pq.offer(new long[]{0, 0, 0});

        while (!pq.isEmpty()) {
            long cost = pq.peek()[0];
            long u = pq.peek()[1];
            int switchUsed = pq.peek()[2];
            pq.poll();

            if (u == n - 1) {
                return cost;
            }

            // If we have already found a better path to this state, skip
            if (cost > dist[u][switchUsed]) {
                continue;
            }

            // Explore neighbors
            if (adj.containsKey(u)) {
                for (long[] edge : adj.get(u)) {
                    long v = edge[0];
                    long w = edge[1];

                    // Regular edge
                    long newCost = cost + w;
                    if (newCost < dist[v][switchUsed]) {
                        dist[v][switchUsed] = newCost;
                        pq.offer(new long[]{newCost, v, switchUsed});
                    }

                    // Reverse edge if switch is not used
                    if (switchUsed == 0) {
                        long newCostRev = cost + 2 * w;
                        if (newCostRev < dist[v][1]) {
                            dist[v][1] = newCostRev;
                            pq.offer(new long[]{newCostRev, v, 1});
                        }
                    }
                }
            }
        }

        // If we can't reach the destination, return -1
        return dist[(int)(n - 1)][0] == Long.MAX_VALUE ? -1 : dist[(int)(n - 1)][0];
    }
}
